css:
* { margin: 0; padding: 0; box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
body { background: #0e0e10; color: white; }
.navbar { display: flex; justify-content: space-between; align-items: center; padding: 24px 60px; }
.brand { font-size: 19px; font-weight: 900; letter-spacing: 0.05em; }
.brand span { color: #38bdf8; }
.nav-links { display: flex; gap: 28px; }
.nav-links a { color: rgba(255,255,255,0.5); text-decoration: none; font-size: 14px; font-weight: 600; }
.nav-links a.active { color: white; }
.nav-btn { background: #38bdf8; color: #0e0e10; border: none; padding: 11px 24px; border-radius: 999px; font-size: 13.5px; font-weight: 800; cursor: pointer; }
.hero { padding: 60px 60px 50px; max-width: 760px; }
.hero h1 { font-size: 60px; font-weight: 900; line-height: 1.1; margin-bottom: 22px; }
.hero h1 span { color: #38bdf8; }
.hero p { color: rgba(255,255,255,0.5); font-size: 16px; line-height: 1.8; max-width: 540px; margin-bottom: 36px; }
.clients { display: flex; gap: 36px; flex-wrap: wrap; }
.clients span { font-size: 16px; font-weight: 900; letter-spacing: 0.1em; color: rgba(255,255,255,0.25); }
.work { padding: 30px 60px 70px; }
.work h2 { font-size: 30px; font-weight: 800; margin-bottom: 30px; }
.work-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 20px; }
.work-card { cursor: pointer; }
.work-card.large { grid-column: span 2; }
.work-img { aspect-ratio: 16/10; background: linear-gradient(150deg, #1c2230, #0e0e10); border-radius: 14px; display: flex; align-items: center; justify-content: center; font-size: 60px; margin-bottom: 14px; transition: 0.2s; }
.work-card.large .work-img { font-size: 90px; }
.work-card:hover .work-img { filter: brightness(1.15); }
.cat { display: block; color: #38bdf8; font-size: 11px; font-weight: 800; text-transform: uppercase; letter-spacing: 0.08em; margin-bottom: 6px; }
.work-card h3 { font-size: 17px; font-weight: 700; }
.team { padding: 60px; background: rgba(255,255,255,0.02); }
.team h2 { font-size: 30px; font-weight: 800; margin-bottom: 30px; }
.team-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(160px, 1fr)); gap: 24px; }
.team-card { text-align: center; }
.avatar { width: 70px; height: 70px; border-radius: 50%; background: linear-gradient(135deg, #38bdf8, #6366f1); display: flex; align-items: center; justify-content: center; font-size: 20px; font-weight: 800; margin: 0 auto 14px; }
.team-card h3 { font-size: 15px; font-weight: 700; margin-bottom: 4px; }
.team-card span { font-size: 12px; color: rgba(255,255,255,0.4); }
.services { padding: 60px; }
.services h2 { font-size: 30px; font-weight: 800; margin-bottom: 30px; }
.service-list { display: flex; flex-direction: column; }
.service-row { display: flex; justify-content: space-between; align-items: center; padding: 22px 0; border-bottom: 1px solid rgba(255,255,255,0.06); flex-wrap: wrap; gap: 8px; }
.service-row:last-child { border-bottom: none; }
.service-row h3 { font-size: 20px; font-weight: 700; }
.service-row p { color: rgba(255,255,255,0.45); font-size: 13.5px; }
.contact { text-align: center; padding: 90px 60px; background: linear-gradient(135deg, rgba(56,189,248,0.08), transparent); }
.contact h2 { font-size: 30px; font-weight: 800; margin-bottom: 12px; }
.contact p { color: rgba(255,255,255,0.5); font-size: 14px; margin-bottom: 26px; }
.contact button { background: #38bdf8; color: #0e0e10; border: none; padding: 16px 34px; border-radius: 999px; font-size: 14px; font-weight: 800; cursor: pointer; }
@media (max-width: 900px) { .navbar, .hero, .work, .team, .services, .contact { padding-left: 24px; padding-right: 24px; } .nav-links { display: none; } .hero h1 { font-size: 38px; } .work-grid { grid-template-columns: 1fr; } .work-card.large { grid-column: span 1; } }

